const services = [
  { name: 'FreiKI App',   url: 'http://freiki-ui:3000/health' },
  { name: 'Paperless',    url: 'http://paperless:8000/api/documents/?page_size=1' },
  { name: 'n8n',          url: 'http://n8n:5678/healthz' },
  { name: 'Mattermost',   url: 'http://mattermost:8065/api/v4/system/ping' },
  { name: 'Whisper',      url: 'http://whisper:9000/' },
];
return [{ json: { services } }];

const items = $input.all();
const serviceNames = $('Pro Service').all().map(i => i.json.name);

const lines = items.map((item, idx) => {
  const name = serviceNames[idx] || '?';
  const ok = !item.json.error && item.json.$response?.statusCode < 400;
  return (ok ? '✅' : '❌') + ' ' + name;
});

// Paperless-Statistiken
return [{ json: { statusLines: lines } }];

const statusLines = $('Ergebnisse aggregieren').first().json.statusLines || [];
const totalDocs = $('Paperless Dokumente zählen').first().json.count || 0;
const tags = $('Paperless Tags holen').first().json.results || [];

const readyTag = tags.find(t => t.name === 'ready-for-rag');
const notYetTag = tags.find(t => t.name === 'not-yet-tagged');

const now = new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });

let msg = `### 📊 FreiKI System-Report – ${now}\n\n`;
msg += `**Services:**\n${statusLines.join('\n')}\n\n`;
msg += `**Paperless:**\n`;
msg += `- Dokumente gesamt: **${totalDocs}**\n`;
if (readyTag) msg += `- Ausstehend (ready-for-rag): Tag-ID ${readyTag.id}\n`;
if (notYetTag) msg += `- Zu taggen (not-yet-tagged): Tag-ID ${notYetTag.id}\n`;

return [{ json: { message: msg } }];

const tagList = $('Tags holen').first().json.results || [];

// ready-for-rag Tag finden
const readyTag = tagList.find(t => t.name.toLowerCase() === 'ready-for-rag');
if (!readyTag) throw new Error('Tag "ready-for-rag" nicht in Paperless gefunden');
const readyId = readyTag.id;

// Bereichs-Tags: alles außer ready-for-rag
const tagMap = {};
for (const t of tagList) {
  if (t.id !== readyId) tagMap[t.id] = t.name.toLowerCase().replace(/[^a-z0-9]/g, '');
}

const docs = $input.first().json.results || [];
const out = [];
for (const doc of docs) {
  if (!doc.tags.includes(readyId)) continue;
  const bereichTagId = doc.tags.find(t => tagMap[t]);
  if (!bereichTagId) continue;
  out.push({
    json: {
      id: doc.id,
      bereich: tagMap[bereichTagId],
      text: doc.content || '',
      source: doc.title,
      source_url: `https://paperless.freiki.com/documents/${doc.id}/details`,
      readyId,
      newTags: doc.tags.filter(id => id !== readyId)
    }
  });
}
return out;

const items = $input.all();
const count = items.length;
const now = new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });
const bereiche = [...new Set(items.map(i => i.json?.bereich).filter(Boolean))];
let msg = `🔄 **RAG-Sync FreiKI** (${now})\n`;
if (count > 0) {
  msg += `${count} Dokument(e) ins Wissen aufgenommen.\n`;
  if (bereiche.length) msg += `Bereiche: ${bereiche.join(', ')}`;
} else {
  msg += 'Keine neuen Dokumente.';
}
return [{ json: { message: msg } }];
